## Code Example
```typescript
export interface Channel { send(msg: string, meta?: any): Promise<void> }
export type ChannelFactory = () => Channel
export class ChannelRegistry {
  private map = new Map<string, ChannelFactory>()
  register(name: string, factory: ChannelFactory) { this.map.set(name, factory) }
  create(name: string): Channel { const f = this.map.get(name); if (!f) throw new Error(`Unknown channel: ${name}`); return f() }
}

export class Notifier {
  constructor(private registry: ChannelRegistry) {}
  async notify(msg: string, channels: string[]) {
    const tasks = channels.map(n => {
      try { return this.registry.create(n).send(msg) } catch (e) { return Promise.reject(e) }
    })
    const results = await Promise.allSettled(tasks)
    return results.map((r, idx) => ({ channel: channels[idx], ok: r.status === 'fulfilled', error: r.status === 'rejected' ? (r.reason as Error).message : undefined }))
  }
}
```

