interface Processor {
  process(ctx: any, data: any): Promise<any>;
}
class ProcessorRegistry {
  private map = new Map<string, () => Processor>();
  register(name: string, factory: () => Processor) { this.map.set(name, factory); }
  create(name: string): Processor { const f = this.map.get(name); if (!f) throw new Error(`Unknown processor: ${name}`); return f(); }
}
class Pipeline {
  constructor(private steps: string[], private registry: ProcessorRegistry) {}
  async run(ctx: any, data: any) {
    let out = data;
    for (const name of this.steps) {
      const p = this.registry.create(name);
      out = await p.process(ctx, out);
    }
    return out;
  }
}
```

