## Code Example
```javascript
// Minimal interface sketch (TypeScript-like)
interface Command {
  execute(ctx: any, payload: any): Promise<void>;
}
interface PluginFactory {
  create(payload: any): Command;
}
class Registry {
  private map = new Map<string, Map<number, PluginFactory>>();

  register(type: string, version: number, factory: PluginFactory) {
    if (!this.map.has(type)) {
      this.map.set(type, new Map());
    }
    this.map.get(type)!.set(version, factory);
  }

  create(type: string, version: number, payload: any): Command | null {
    return this.map.get(type)?.get(version)?.create(payload) || null;
  }
}
```

