## Code Example

```javascript
interface ValidationError { field: string; message: string; }

interface Validator<T = any> {
  validate(record: T): Promise<ValidationError[]>;
}

class Registry<T = any> {
  private map = new Map<string, Validator<T>>();
  register(name: string, v: Validator<T>) { this.map.set(name, v); }
  get(name: string): Validator<T> | undefined { return this.map.get(name); }
}

async function runValidators<T>(record: T, validators: Validator<T>[]): Promise<ValidationError[]> {
  const results = await Promise.all(validators.map(v => v.validate(record).catch(() => [])));
  return results.flat();
}
```

